#include <stdio.h>
#include <stdlib.h>
#include <time.h>

int main() {
    int T, N, M;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        int* A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        double expectedValue = 0.0;
        int totalCombinations = 1;
        for (int i = 0; i < N; i++) {
            if (A[i] == 0) {
                totalCombinations *= M;
            }
        }
        for (int combination = 0; combination < totalCombinations; combination++) {
            int* meatballs = (int*)malloc(N * sizeof(int));
            int currentCombination = combination;
            for (int i = 0; i < N; i++) {
                if (A[i] == 0) {
                    meatballs[i] = currentCombination % M + 1;
                    currentCombination /= M;
                } else {
                    meatballs[i] = A[i];
                }
            }
            int maxConsecutive = 1;
            int currentConsecutive = 1;
            for (int i = 1; i < N; i++) {
                if (meatballs[i] == meatballs[i - 1]) {
                    currentConsecutive++;
                } else {
                    maxConsecutive = (maxConsecutive > currentConsecutive) ? maxConsecutive : currentConsecutive;
                    currentConsecutive = 1;
                }
            }
            maxConsecutive = (maxConsecutive > currentConsecutive) ? maxConsecutive : currentConsecutive;
            expectedValue += (double)maxConsecutive / totalCombinations;
            free(meatballs);
        }
        printf("%.6f\n", expectedValue);
        free(A);
    }
    return 0;
}

