    N, M = map(int, input().split())
    A = list(map(int, input().split()))
    expectedValue = 0.0
    totalCombinations = 1
    for i in range(N):
        if A[i] == 0:
            totalCombinations *= M
    for combination in range(totalCombinations):
        meatballs = [0] * N
        currentCombination = combination
        for i in range(N):
            if A[i] == 0:
                meatballs[i] = currentCombination % M + 1
                currentCombination //= M
            else:
                meatballs[i] = A[i]
        maxConsecutive = 1
        currentConsecutive = 1
        for i in range(1, N):
            if meatballs[i] == meatballs[i - 1]:
                currentConsecutive += 1
            else:
                maxConsecutive = max(maxConsecutive, currentConsecutive)
                currentConsecutive = 1
        maxConsecutive = max(maxConsecutive, currentConsecutive)
        expectedValue += maxConsecutive / totalCombinations
    print(f"{expectedValue:.6f}")

